EXAMPLE_PROMPT = ChatPromptTemplate.from_messages(
    [
        ("human", "講話の文字起こし:\n---\n{input}\n---"),
        ("ai", "{output}"),
    ]
)

FEW_SHOT_PROMPT = FewShotChatMessagePromptTemplate(
    examples=FEW_SHOT_EXAMPLES,
    example_prompt=EXAMPLE_PROMPT,
)

FINAL_PROMPT = ChatPromptTemplate.from_messages(
    [
        ("system", SYSTEM_PROMPT),
        FEW_SHOT_PROMPT,
        (
            "human",
            "講話の文字起こし:\n---\n{text}\n---\n上記の書式に従ってMarkdownのノートを出力してください。",
        ),
    ]
)


def summarize_text(
    text: str,
    settings: Settings,
    provider: Provider | None = None,
    profile: Profile | None = None,
) -> str:
    llm = get_llm(settings=settings, provider=provider, profile=profile)
    messages = FINAL_PROMPT.format_messages(text=text)
    response = llm.invoke(messages)
    summary = _extract_response_text(response).strip()
    if not summary:
        raise ProcessingError("The LLM returned an empty summary.")
    return summary


def _extract_response_text(response: object) -> str:
    content = getattr(response, "content", response)
    if isinstance(content, str):
        return content
    if isinstance(content, list):
        parts: list[str] = []
        for item in content:
            if isinstance(item, dict) and "text" in item:
                parts.append(str(item["text"]))
            else:
                parts.append(str(item))
        return "\n".join(part for part in parts if part).strip()
    return str(content)
